+        if (expected != actual) {
+            self.failed += 1;
+            return error.AssertionFailed;
+        }
+        self.passed += 1;
+    }
+
+    pub fn assertTrue(self: *@This(), value: bool) !void {
+        if (!value) {
+            self.failed += 1;
