+    pub fn fetchone(self: *@This()) ?Row {
+        _ = self;
+        return null;
+    }
+    
+    pub fn fetchmany(self: *@This(), size: ?usize) []const Row {
+        _ = self; _ = size;
+        return &.{};
+    }
+    
+    pub fn fetchall(self: *@This()) []const Row {
+        _ = self;
