+    pub fn namelist(self: @This()) []const []const u8 {
+        var names: [][]const u8 = self.allocator.alloc([]const u8, self.files.items.len) catch return &.{};
+        for (self.files.items, 0..) |f, i| names[i] = f.filename;
+        return names;
